/*
 * DMA Controller Implementation in C
 * Simulates register structures and transfer logic for educational purposes
 */

#include <stdio.h>
#include <stdint.h>
#include <stdbool.h>
#include <string.h>

/* DMA Controller Register Offsets (typical 8237 DMAC) */
#define DMA_BASE_ADDR 0x00
#define DMA_COUNT_REG 0x01
#define DMA_CONTROL_REG 0x02
#define DMA_STATUS_REG 0x03

/* Control Register Bit Definitions */
#define CTRL_DIR_MEMORY_TO_IO (1 << 4) /* 0 = Read from IO, 1 = Write to IO */
#define CTRL_MODE_MASK (3 << 6) /* Transfer mode bits */
#define CTRL_ENABLE (1 << 7) /* DMA enable */

/* Transfer Modes */	ypedef enum {
 DMA_MODE_DEMAND = 0,
 DMA_MODE_SINGLE = 1,
 DMA_MODE_BLOCK = 2,
 DMA_MODE_CASCADE = 3
} DMA_TransferMode;

/* DMA Channel structure */
typedef struct {
 volatile uint16_t address; /* Starting memory address */
 volatile uint16_t count; /* Number of words to transfer */
 volatile uint8_t control; /* Control register */
 volatile uint8_t status; /* Status register */
 bool active; /* Channel active flag */
} DMA_Channel;

/* DMA Controller structure */
typedef struct {
 DMA_Channel channels[4]; /* 4 DMA channels (typical 8237) */
 volatile uint8_t temp_register; /* Temporary holding register */
 volatile uint8_t command; /* Command register */
 volatile uint8_t mask; /* Mask register */
} DMA_Controller;

/* Simulated system memory */
#define MEMORY_SIZE 65536
static uint8_t system_memory[MEMORY_SIZE];

/* Global DMA controller instance */
static DMA_Controller dmac = {0};

/* Function prototypes */
void dma_init_channel(int channel, uint32_t address, uint16_t count, bool to_memory);
void dma_start_transfer(int channel);
bool dma_check_complete(int channel);
void dma_setup_transfer(int channel, void* src, void* dest, uint16_t bytes);
void simulate_cpu_bus_cycle(void);

/* Initialize a DMA channel with transfer parameters */
void dma_init_channel(int channel, uint32_t address, uint16_t count, bool to_memory) {
 if (channel < 0 || channel >= 4) {
 printf("Error: Invalid DMA channel %d\n", channel);
 return;
 }

 DMA_Channel* chan = &dmac.channels[channel];

 /* Set base address (auto-incremented during transfer) */
 chan->address = (uint16_t)(address & 0xFFFF);

 /* Set word count (transfers = count + 1) */
 chan->count = count;

 /* Configure control register */
 chan->control = CTRL_ENABLE;
 if (!to_memory) {
 chan->control |= CTRL_DIR_MEMORY_TO_IO; /* Writing to I/O device */
 }

 chan->status = 0;
 chan->active = false;

 printf("DMA Channel %d initialized:\n", channel);
 printf(" Address: 0x%04X\n", chan->address);
 printf(" Count: %d words\n", count + 1);
 printf(" Direction: %s\n", to_memory ? "I/O -> Memory" : "Memory -> I/O");
}

/* Simulate bus request and grant */
bool dma_request_bus(void) {
 printf("\n[DMAC] Requesting bus control (BR/HOLD signal)\n");

 /* Simulate CPU acknowledging bus request */
 simulate_cpu_bus_cycle();

 printf("[CPU] Bus granted to DMAC (BG/HLDA signal)\n");
 printf("[DMAC] Bus control acquired\n");

 return true;
}

/* Simulate releasing bus back to CPU */
void dma_release_bus(void) {
 printf("[DMAC] Releasing bus control to CPU\n");
 simulate_cpu_bus_cycle();
 printf("[CPU] Bus control reacquired\n");
}

/* Perform actual data transfer (Cycle Stealing Mode) */
void dma_perform_cycle_stealing(int channel, void* io_buffer, uint16_t byte_count) {
 DMA_Channel* chan = &dmac.channels[channel];
 uint8_t* io_data = (uint8_t*)io_buffer;
 uint16_t transferred = 0;

 printf("\n=== Starting Cycle Stealing Transfer ===\n");

 while (transferred < byte_count) {
 /* Request bus for one word */
 dma_request_bus();

 /* Check if reading from I/O or writing to I/O */
 if (chan->control & CTRL_DIR_MEMORY_TO_IO) {
 /* Memory -> I/O device */
 uint8_t data = system_memory[chan->address + transferred];
 io_data[transferred] = data;
 printf(" Word %d: Memory[0x%04X]=0x%02X -> I/O Device\n", 
 transferred / 4, chan->address + transferred, data);
 } else {
 /* I/O device -> Memory */
 system_memory[chan->address + transferred] = io_data[transferred];
 printf(" Word %d: I/O Device=0x%02X -> Memory[0x%04X]\n", 
 transferred / 4, io_data[transferred], chan->address + transferred);
 }

 transferred += 4; /* One word = 4 bytes */
 chan->count--;

 /* Release bus after each word (cycle stealing) */
 dma_release_bus();

 /* Small delay to show the cycle stealing effect */
 }

 printf("=== Transfer Complete: %d bytes ===\n", transferred);
}

/* Perform Burst Mode Transfer */
void dma_perform_burst_transfer(int channel, void* io_buffer, uint16_t byte_count) {
 DMA_Channel* chan = &dmac.channels[channel];
 uint8_t* io_data = (uint8_t*)io_buffer;
 uint16_t transferred = 0;

 printf("\n=== Starting Burst Mode Transfer ===\n");

 /* Request bus and hold for entire transfer */
 dma_request_bus();

 while (transferred < byte_count) {
 if (chan->control & CTRL_DIR_MEMORY_TO_IO) {
 system_memory[chan->address + transferred] = io_data[transferred];
 } else {
 io_data[transferred] = system_memory[chan->address + transferred];
 }
 transferred += 4;
 chan->count--;

 printf(" Transferred word %d (bus still held)\n", transferred / 4);
 }

 /* Release bus only after all transfers complete */
 dma_release_bus();

 printf("=== Burst Transfer Complete ===\n");
}

/* Simulate CPU bus cycle */
void simulate_cpu_bus_cycle(void) {
 /* In real hardware, CPU would complete current instruction */
}

/* Main demonstration */
int main(void) {
 printf("========================================\n");
 printf(" DMA Controller Simulation (C)\n");
 printf("========================================\n");

 /* Sample I/O data (simulating data from a device) */
 uint8_t device_buffer[16] = {
 0x48, 0x65, 0x6C, 0x6C, /* "Hell" */
 0x6F, 0x20, 0x57, 0x6F, /* "o Wo" */
 0x72, 0x6C, 0x64, 0x00 /* "rld" */
 };

 /* Initialize DMA Channel 0 for I/O -> Memory transfer */
 dma_init_channel(0, 0x1000, 2, true); /* to_memory = true */

 /* Perform cycle stealing transfer */
 dma_perform_cycle_stealing(0, device_buffer, 12);

 printf("\n----------------------------------------\n");

 /* Initialize Channel 1 for burst mode */
 dma_init_channel(1, 0x2000, 2, true);

 /* Perform burst transfer */
 dma_perform_burst_transfer(1, device_buffer, 12);

 printf("\n========================================\n");
 printf(" Simulation Complete\n");
 printf("========================================\n");

 /* Display memory contents */
 printf("\nMemory at 0x1000 (Cycle Stealing):\n");
 for (int i = 0; i < 12; i++) {
 printf("%02X ", system_memory[0x1000 + i]);
 }
 printf("\n");

 return 0;
}
